const GAME_GEAR_ICON_KEY_MAP: Record<string, keyof typeof GAME_ICON_PATHS> = {
  Shirt: 'tshirt',
  LongSleeveShirt: 'longSleeveShirt',
  Jacket: 'layeredArmor',
  Pants: 'trousers',
  Shorts: 'shorts',
  CasualShorts: 'shorts',
  BibShorts: 'shorts',
  Hand: 'winterGloves',
  Footprints: 'footprint',
  Snowflake: 'snowflake',
  CloudRain: 'heavyRain',
  Umbrella: 'umbrella',
  Wind: 'cloudRing',
  Sun: 'sun',
  Sunscreen: 'sunscreenSpray',
  Glasses: 'sunglasses',
  Thermometer: 'thermometerHot',
  Layers: 'stack',
  WoolCap: 'winterHat',
};

/** Renders a game-icons glyph for a kit icon key. */
export function GameGearIcon({
  iconKey,
  size,
  color,
  style,
}: Readonly<{ iconKey: string; size: number; color: string; style?: object }>) {
  const pathKey = GAME_GEAR_ICON_KEY_MAP[iconKey] ?? 'tshirt';
  return (
    <Svg viewBox="0 0 512 512" width={size} height={size} style={style}>
      <Path fill={color} d={GAME_ICON_PATHS[pathKey]} />
    </Svg>
  );
}

/** Shared rounded button styles (not used for burst condition badges). */
export function makeButtonStyles(c: WheelyPalette) {
  return StyleSheet.create({
    base: {
      flexDirection: 'row',
      alignItems: 'center',
      justifyContent: 'center',
      gap: Spacing.two,
      borderRadius: ButtonRadius,
      borderWidth: 2,
      borderColor: c.border,
      paddingHorizontal: Spacing.three,
      paddingVertical: Spacing.two,
      minHeight: 40,
    },
    primary: {
      backgroundColor: c.primary,
    },
    primaryLabel: {
      color: c.primaryInk,
    },
    surface: {
      backgroundColor: c.paper,
    },
    label: {
      color: c.ink,
      fontFamily: Fonts.body,
      fontWeight: '400',
      ...Type.caption,
    },
    pressed: {
      opacity: PressedOpacity,
    },
  });
}

/** Maps an Open-Meteo WMO weather code to a Lucide icon. */
export function weatherIconFor(code: number | null | undefined): LucideIcon {
  if (code == null) return Cloud;
  if (code <= 1) return Sun;
  if (code <= 3) return CloudSun;
  if (code <= 48) return CloudFog;
  if (code <= 65) return CloudRain;
  if (code <= 77) return CloudSnow;
  if (code <= 82) return CloudRain;
  if (code <= 86) return CloudSnow;
  if (code <= 99) return CloudLightning;
  return Cloud;
}

/** Maps an Open-Meteo WMO weather code to an SF Symbol name (iOS). */
export function weatherSfSymbol(code: number | null | undefined): string {
  if (code == null) return 'cloud.fill';
  if (code <= 1) return 'sun.max.fill';
  if (code <= 3) return 'cloud.sun.fill';
  if (code <= 48) return 'cloud.fog.fill';
  if (code <= 65) return 'cloud.rain.fill';
  if (code <= 77) return 'cloud.snow.fill';
  if (code <= 82) return 'cloud.rain.fill';
  if (code <= 86) return 'cloud.snow.fill';
  if (code <= 99) return 'cloud.bolt.fill';
  return 'cloud.fill';
}

/** Gear tip icon lookup keyed by gear item name from domain. */
export const GEAR_ICONS: Record<string, LucideIcon> = {
  Shorts: UserRound,
  CasualShorts: UserRound,
  BibShorts: Bike,
  Pants: PersonStanding,
  Jacket: Layers,
  Shirt,
  Layers,
  Hand,
  Footprints,
  Snowflake,
  CloudRain,
  Umbrella,
  Wind,
  Sun,
  Glasses,
  Thermometer,
};

/** Narrows an unknown value to a valid `Condition`, defaulting to `'fair'`. */
export function asCondition(value: unknown): Condition {
  return value === 'good' ||
    value === 'fair' ||
    value === 'marginal' ||
    value === 'poor' ||
    value === 'bad'
    ? value
    : 'fair';
}

/** Formats a Date or ISO string as a locale time string. */
export function formatTime(value: Date | string | null | undefined): string {
  if (!value) return '';
  return new Date(value).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

